import streamlit as stimport pandas as pdimport plotly.express as pximport osst.set_page_config(page_title="Il Mercato - Inteligencia Operativa", layout="wide", page_icon="📊")st.title("📊 Dashboard de Excelencia - Il Mercato")st.markdown("---")@st.cache_datadef cargar_datos_seguros():    archivos = [f for f in os.listdir('.') if f.endswith('.xlsx') and not f.startswith('~$')]    if not archivos:         return None    archivo_objetivo = archivos[0]        try:        xls = pd.ExcelFile(archivo_objetivo)    except:        return None            hojas = [h for h in xls.sheet_names if h.upper() != 'TOTAL']    if not hojas:         hojas = xls.sheet_names            lista_dfs = []    for hoja in hojas:        try:            df_hoja = pd.read_excel(archivo_objetivo, sheet_name=hoja)            if len(df_hoja.columns) >= 2:                # Limpiamos los nombres de las columnas de ESTA hoja específicamente                df_hoja.columns = [str(c).strip() for c in df_hoja.columns]                df_hoja['Restaurante_Origen'] = str(hoja).strip().upper()                                # Asegurar que la fecha no rompa nada                if 'Submitted at' in df_hoja.columns:                    df_hoja['Submitted at'] = df_hoja['Submitted at'].astype(str)                                    lista_dfs.append(df_hoja)        except:            continue                if not lista_dfs:         return None            df_unido = pd.concat(lista_dfs, ignore_index=True, sort=False)    return df_unido# Intentar cargar la base de datosdf = cargar_datos_seguros()if df is not None:    try:        # Nombres de las columnas exactas de tu Jotform/Excel        col_mesero = 'Selecciona a la persona que te atendió / Select the person who assisted you'        col_calif = 'Califica la atención recibida / How would you rate your experience?'        col_comentario = 'Cuéntanos cómo fue tu experiencia / Tell us about your visit'        # Asegurar que la columna de calificación sea numérica a la fuerza        if col_calif in df.columns:            df[col_calif] = pd.to_numeric(df[col_calif], errors='coerce')        # --- BARRA LATERAL ---        st.sidebar.header("🎯 Filtros de Operación")        unidades = sorted(df['Restaurante_Origen'].unique())        sel_unidades = st.sidebar.multiselect("Selecciona las unidades:", unidades, default=unidades)                df_f = df[df['Restaurante_Origen'].isin(sel_unidades)].copy()        # --- METRICAS PRINCIPALES ---        c1, c2, c3, c4 = st.columns(4)        c1.metric("Total Encuestas", f"{len(df_f)} respuestas")                if col_calif in df_f.columns:            promedio_gen = df_f[col_calif].mean()            c2.metric("Promedio General", f"{promedio_gen:.2f} ⭐" if not pd.isna(promedio_gen) else "N/A")                        # Conteo seguro de comentarios de 1 o 2 estrellas            malos_comentarios = df_f[df_f[col_calif] <= 2].dropna(subset=[col_calif])            c3.metric("Alertas (1-2 ⭐)", len(malos_comentarios))        else:            c2.metric("Promedio General", "No detectado")            c3.metric("Alertas (1-2 ⭐)", "0")            malos_comentarios = pd.DataFrame()                    c4.metric("Meseros Evaluados", df_f[col_mesero].dropna().nunique() if col_mesero in df_f.columns else 0)        st.markdown("---")        # --- SECCIÓN DE TOPS (MESEROS) ---        st.subheader("🏆 Desempeño del Equipo de Servicio")        t1, t2 = st.columns(2)        # TOP 10 VOLUMEN        with t1:            st.markdown("##### 🔝 Top 10 Meseros (Más Encuestas)")            if col_mesero in df_f.columns and not df_f[col_mesero].dropna().empty:                top_volumen = df_f[col_mesero].value_counts().nlargest(10).reset_index()                top_volumen.columns = ['Mesero', 'Cantidad']                fig_vol = px.bar(top_volumen, x='Cantidad', y='Mesero', orientation='h',                                  color='Cantidad', color_continuous_scale='Blues', text_auto=True)                fig_vol.update_layout(yaxis={'categoryorder':'total ascending'})                st.plotly_chart(fig_vol, use_container_width=True)            else:                st.info("No hay suficientes datos de meseros para mostrar el volumen.")        # TOP 10 CALIFICACIÓN        with t2:            st.markdown("##### ⭐ Top 10 Meseros (Mejor Calificación)")            if col_mesero in df_f.columns and col_calif in df_f.columns and not df_f[col_mesero].dropna().empty:                # Filtrar meseros con al menos 2 encuestas para que sea estadísticamente justo                conteo_votos = df_f[col_mesero].value_counts()                meseros_activos = conteo_votos[conteo_votos >= 2].index                df_meseros_activos = df_f[df_f[col_mesero].isin(meseros_activos)]                                if not df_meseros_activos.empty:                    top_calif = df_meseros_activos.groupby(col_mesero)[col_calif].mean().nlargest(10).reset_index()                    top_calif.columns = ['Mesero', 'Promedio']                    fig_cal = px.bar(top_calif, x='Promedio', y='Mesero', orientation='h',                                     color='Promedio', color_continuous_scale='Reds', text_auto='.2f', range_x=[0,5])                    fig_cal.update_layout(yaxis={'categoryorder':'total ascending'})                    st.plotly_chart(fig_cal, use_container_width=True)                else:                    st.info("Se necesitan más encuestas por mesero para calcular el Top Calidad.")            else:                st.info("Faltan columnas de calificación o nombres de meseros.")        # --- SECCIÓN DE MALOS COMENTARIOS (ALERTAS) ---        if not malos_comentarios.empty:            st.markdown("---")            st.subheader("⚠️ Atención Inmediata: Comentarios Negativos")            st.error(f"Se han registrado {len(malos_comentarios)} experiencias con baja puntuación.")                        columnas_existentes = [c for c in ['Restaurante_Origen', col_mesero, col_calif, col_comentario] if c in df_f.columns]            st.dataframe(malos_comentarios[columnas_existentes], use_container_width=True)        # --- PARTICIPACIÓN GENERAL POR RESTAURANTE ---        st.markdown("---")        st.subheader("🏢 Participación por Centro de Consumo")        conteos_rest = df_f['Restaurante_Origen'].value_counts().reset_index()        conteos_rest.columns = ['Restaurante', 'Encuestas']        fig_rest = px.bar(conteos_rest, x='Encuestas', y='Restaurante', orientation='h',                          color='Encuestas', color_continuous_scale='Blugrn', text_auto=True)        fig_rest.update_layout(yaxis={'categoryorder':'total ascending'})        st.plotly_chart(fig_rest, use_container_width=True)        # --- DATA MASTERS ---        st.markdown("---")        st.subheader("📋 Consolidado General de Datos")        st.dataframe(df_f, use_container_width=True)    except Exception as e:        st.error(f"Ocurrió un error al procesar el Dashboard interno: {e}")else:    st.error("No se pudo leer el archivo de Excel. Revisa que esté cerrado y en la misma carpeta que este script.")